const users = [
  { id: 1, name: 'Alice', age: 30, active: true },
  { id: 2, name: 'Bob', age: 25, active: false },
  { id: 3, name: 'Carol', age: 35, active: true },
  { id: 4, name: 'Dave', age: 28, active: true },
];

// map: transform each item into something new
const names = users.map(user => user.name);
// ['Alice', 'Bob', 'Carol', 'Dave']

// filter: keep only items that match a condition
const activeUsers = users.filter(user => user.active);
// [Alice, Carol, Dave]

// find: get the first item that matches
const bob = users.find(user => user.name === 'Bob');
// { id: 2, name: 'Bob', ... }

// some / every: check if any / all items match
const hasInactive = users.some(user => !user.active);  // true
const allActive = users.every(user => user.active);     // false

// reduce: combine all items into a single value
const totalAge = users.reduce((sum, user) => sum + user.age, 0);
// 118

// Chaining: filter active users, get their names, sort alphabetically
const sortedActiveNames = users
  .filter(user => user.active)
  .map(user => user.name)
  .sort();
// ['Alice', 'Carol', 'Dave']

// flatMap: map + flatten in one step
const sentences = ['hello world', 'foo bar'];
const words = sentences.flatMap(s => s.split(' '));
// ['hello', 'world', 'foo', 'bar']

// Selecting elements
const heading = document.querySelector('h1');
const allButtons = document.querySelectorAll('button');
const byId = document.getElementById('my-element');

// Modifying elements
heading.textContent = 'New Title';         // Change text
heading.style.color = 'blue';              // Change inline style
heading.classList.add('highlighted');       // Add a CSS class
heading.classList.toggle('visible');        // Toggle a class
heading.setAttribute('data-id', '123');    // Set an attribute

// Creating elements
const newParagraph = document.createElement('p');
newParagraph.textContent = 'I was created with JavaScript!';
document.body.appendChild(newParagraph);

// Event listeners
const button = document.querySelector('#my-button');
button.addEventListener('click', (event) => {
  console.log('Button clicked!', event.target);
});

// Remove event listener (must pass the same function reference)
function handleClick(event) {
  console.log('Clicked!');
}
button.addEventListener('click', handleClick);
button.removeEventListener('click', handleClick);
